// Cycle through the pin list one per run, then queue the pin to every
// configured Buffer channel. buffer_get_channel.py prints channel ids AND
// Pinterest board ids. Leave any id as PASTE_... and that channel is skipped.
const CHANNELS = [
  {
    name: 'pinterest',
    id: '6a47b7055ab6d2f1069dea9f',
    // Pinterest requires a board per pin (boardServiceId). Keys must match
    // the "board" field in pins.json; unmapped names use defaultBoard.
    boards: {
      'Asia Travel: Japan, Vietnam, Korea & More': '609956411972753421',
      'Travel Tech: eSIM, Insurance & Booking': '609956411972752122',
      'Packing Light & Capsule Wardrobe': '609956411972752122',
      'Cultural Travel & Etiquette': '609956411972753420',
      'Travel Prep Checklists': '609956411972752122',
      'Country Profiles & City Guides': '609956411972753421',
    },
    defaultBoard: '609956411972753421',
  },
  { name: 'x', id: '6a47b8035ab6d2f1069def94' },
];

const data = $input.first().json;
const pins = (data && data.pins) || [];
if (!pins.length) { throw new Error('pins.json empty'); }

const store = $getWorkflowStaticData('global');
let idx = typeof store.idx === 'number' ? store.idx : 0;
if (idx >= pins.length) idx = 0;
const pin = pins[idx];
store.idx = idx + 1;

const hour = new Date().getHours();
const query = 'mutation Create($input: CreatePostInput!) { createPost(input: $input) { __typename ... on PostActionSuccess { post { id } } ... on MutationError { message } } }';

// Per-channel text. Pinterest: the post text becomes the pin description;
// title and destination link travel in metadata.pinterest instead.
const hook = (pin.description || '').split('. ')[0];
const texts = {
  pinterest: (pin.description || pin.title).slice(0, 480),
  x: (pin.title + '\n\n' + hook + '.\n\n' + pin.link).slice(0, 275),
};

const items = [];
for (const ch of CHANNELS) {
  if (!ch.id || ch.id.startsWith('PASTE_')) continue;
  if (ch.morningOnly && hour >= 12) continue;

  const input = {
    text: texts[ch.name] || texts.pinterest,
    channelId: ch.id,
    schedulingType: 'automatic',
    mode: 'addToQueue',
    assets: [ { image: { url: pin.image } } ],
  };

  if (ch.name === 'pinterest') {
    const boardServiceId = (ch.boards && ch.boards[pin.board]) || ch.defaultBoard;
    if (!boardServiceId || boardServiceId.startsWith('PASTE_')) {
      throw new Error('Pinterest board id missing for "' + pin.board + '" - fill boards/defaultBoard in CHANNELS.');
    }
    input.metadata = { pinterest: {
      title: pin.title.slice(0, 100),
      url: pin.link,
      boardServiceId: boardServiceId,
    } };
  }

  items.push({ json: { channel: ch.name, slug: pin.slug, graphqlBody: { query, variables: { input } } } });
}

if (!items.length) { throw new Error('No channels configured - paste your channel ids into CHANNELS at the top of this node.'); }
return items;
